package picod

import (
	"bytes"
	"context"
	"fmt"
	"net/http"
	"os/exec"
	"time"

	"github.com/gin-gonic/gin"
)

func (s *Server) ExecuteHandler(c *gin.Context) {
	var req ExecuteRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if len(req.Command) == 0 {
		c.JSON(http.StatusBadRequest, gin.H{"error": "command is required"})
		return
	}

	ctx := c.Request.Context()
	stdout, stderr, exitCode, err := runCommand(ctx, req.Command, req.WorkingDir, req.Env)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	duration := time.Since(s.startTime).Seconds()

	resp := ExecuteResponse{
		Stdout:    stdout.String(),
		Stderr:    stderr.String(),
		ExitCode:  exitCode,
		Duration:  duration,
		StartTime: s.startTime.Format(time.RFC3339),
		EndTime:   time.Now().Format(time.RFC3339),
	}

	c.JSON(http.StatusOK, resp)
}

func runCommand(ctx context.Context, command []string, workingDir string, env map[string]string) (stdout, stderr bytes.Buffer, exitCode int, err error) {
	timeoutStr := "60s"
	ctxWithTimeout, cancel := context.WithTimeout(ctx, 60*time.Second)
	defer cancel()

	if timeoutStr != "" {
		if d, err := time.ParseDuration(timeoutStr); err == nil {
			ctxWithTimeout, cancel = context.WithTimeout(ctx, d)
			defer cancel()
		}
	}

	cmd := exec.CommandContext(ctxWithTimeout, command[0], command[1:]...)
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	if workingDir != "" {
		cmd.Dir = workingDir
	}

	for k, v := range env {
		cmd.Env = append(cmd.Env, k+"="+v)
	}

	if err := cmd.Run(); err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			exitCode = exitErr.ExitCode()
		} else {
			exitCode = 1
		}

		if ctxWithTimeout.Err() == context.DeadlineExceeded {
			exitCode = TimeoutExitCode
			err = fmt.Errorf("command timed out")
		}
		return
	}

	exitCode = 0
	return
}

