package picod

import (
	"fmt"
	"path/filepath"
	"strings"
)

func sanitizePath(p string) (string, error) {
	if p == "" {
		return "", nil
	}

	p = filepath.Clean(p)

	if strings.HasPrefix(p, "..") {
		return "", fmt.Errorf("path escape detected: %s", p)
	}

	if filepath.IsAbs(p) {
		p = strings.TrimPrefix(p, "/")
	}

	return p, nil
}

