func runCommand(ctx context.Context, command []string, workingDir string, env map[string]string) (stdout bytes.Buffer, stderr bytes.Buffer, exitCode int, runErr error) {
	timeoutStr := "60s"
	ctxWithTimeout, cancel := context.WithTimeout(ctx, 60*time.Second)
	defer cancel()

	if timeoutStr != "" {
		if d, parseErr := time.ParseDuration(timeoutStr); parseErr == nil {
			ctxWithTimeout, cancel = context.WithTimeout(ctx, d)
			defer cancel()
		}
	}

	cmd := exec.CommandContext(ctxWithTimeout, command[0], command[1:]...)
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	if workingDir != "" {
		cmd.Dir = workingDir
	}

	for k, v := range env {
		cmd.Env = append(cmd.Env, k+"="+v)
	}

	if runErr = cmd.Run(); runErr != nil {
		if exitErr, ok := runErr.(*exec.ExitError); ok {
			exitCode = exitErr.ExitCode()
		} else {
			exitCode = 1
		}

		if ctxWithTimeout.Err() == context.DeadlineExceeded {
			exitCode = TimeoutExitCode
			runErr = fmt.Errorf("command timed out")
		}
		return
	}

	exitCode = 0
	return
}

