package picod

import (
	"crypto/rsa"
	"crypto/x509"
	"encoding/base64"
	"encoding/pem"
	"errors"
	"fmt"
	"io"
	"net/http"
	"os"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
)

type AuthManager struct {
	publicKey *rsa.PublicKey
	mu        sync.RWMutex
}

func (am *AuthManager) LoadPublicKeyFromEnv() error {
	keyData := os.Getenv(PublicKeyEnvVar)
	if keyData == "" {
		return nil
	}

	decoded, err := base64.StdEncoding.DecodeString(keyData)
	if err != nil {
		return fmt.Errorf("failed to decode public key: %w", err)
	}

	block, _ := pem.Decode(decoded)
	if block == nil {
		return errors.New("failed to parse PEM block")
	}

	pub, err := x509.ParsePKIXPublicKey(block.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse public key: %w", err)
	}

	rsaPub, ok := pub.(*rsa.PublicKey)
	if !ok {
		return errors.New("public key is not RSA")
	}

	am.mu.Lock()
	am.publicKey = rsaPub
	am.mu.Unlock()

	return nil
}

func (am *AuthManager) AuthMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		am.mu.RLock()
		hasKey := am.publicKey != nil
		am.mu.RUnlock()

		if !hasKey {
			c.Next()
			return
		}

		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "missing authorization header"})
			return
		}

		const bearerPrefix = "Bearer "
		if len(authHeader) < len(bearerPrefix) || authHeader[:len(bearerPrefix)] != bearerPrefix {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid authorization format"})
			return
		}

		tokenString := authHeader[len(bearerPrefix):]

		token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
			if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
				return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
			}
			am.mu.RLock()
			defer am.mu.RUnlock()
			return am.publicKey, nil
		})

		if err != nil || !token.Valid {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid token"})
			return
		}

		c.Request.Body = io.NopCloser(http.MaxBytesReader(c.Writer, c.Request.Body, MaxBodySize))
		c.Next()
	}
}

