	"encoding/json"
	"fmt"
	"os"
	"time"

	"github.com/volcano-sh/agentcube/pkg/common/types"

	"github.com/redis/go-redis/v9"
)

const (
	sessionPrefix        = "session:"
	expiryIndexKey       = "session:expiry"
	lastActivityIndexKey = "session:last_activity"
)

type redisStore struct {
	cli                  *redis.Client
	sessionPrefix        string
	expiryIndexKey       string
	lastActivityIndexKey string
}

func newRedisStore() (Store, error) {
	addr := os.Getenv("REDIS_ADDR")
	if addr == "" {
		addr = "localhost:6379"
	}

	password := ""
	passwordRequired := os.Getenv("REDIS_PASSWORD_REQUIRED")
	if passwordRequired == "true" || passwordRequired == "" {
		password = os.Getenv("REDIS_PASSWORD")
	}

	opts, err := makeRedisOptions()
	if err != nil {
		return nil, err
	}

	if addr != "" {
		opts.Addr = addr
	}
	if password != "" {
		opts.Password = password
	}

	cli := redis.NewClient(opts)

	return &redisStore{
		cli:                  cli,
		sessionPrefix:        sessionPrefix,
		expiryIndexKey:       expiryIndexKey,
		lastActivityIndexKey: lastActivityIndexKey,
	}, nil
}

func makeRedisOptions() (*redis.Options, error) {
	return &redis.Options{
		DB:       0,
		Protocol: 2,
	}, nil
}

func (r *redisStore) Ping(ctx context.Context) error {
	pong, err := r.cli.Ping(ctx).Result()
	if err != nil {
		return err
	}
	if pong != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", pong)
	}
	return nil
}

func (r *redisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := r.sessionPrefix + sessionID
	data, err := r.cli.Get(ctx, key).Bytes()
	if err == redis.Nil {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal(data, &sandbox); err != nil {
		return nil, err
	}

	return &sandbox, nil
}

func (r *redisStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	key := r.sessionPrefix + sandbox.SessionID

	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	expiresAt := sandbox.ExpiresAt
	if expiresAt.IsZero() {
		expiresAt = time.Now().Add(8 * time.Hour)
	}

	ttl := time.Until(expiresAt)
	if ttl <= 0 {
		ttl = 8 * time.Hour
	}

	pipe := r.cli.Pipeline()

	setCmd := pipe.SetNX(ctx, key, data, ttl)

	expiryScore := float64(expiresAt.Unix())
	pipe.ZAdd(ctx, r.expiryIndexKey, redis.Z{
		Score:  expiryScore,
		Member: sandbox.SessionID,
	})

	lastActivity := sandbox.CreatedAt
	if sandbox.LastActivity != nil {
		lastActivity = *sandbox.LastActivity
	}
	pipe.ZAdd(ctx, r.lastActivityIndexKey, redis.Z{
		Score:  float64(lastActivity.Unix()),
		Member: sandbox.SessionID,
	})

	_, err = pipe.Exec(ctx)
	if err != nil {
		return err
	}

	if !setCmd.Val() {
		return fmt.Errorf("sandbox already exists for session %s", sandbox.SessionID)
	}

	return nil
}

func (r *redisStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	key := r.sessionPrefix + sandbox.SessionID

	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	expiresAt := sandbox.ExpiresAt
	if expiresAt.IsZero() {
		expiresAt = time.Now().Add(8 * time.Hour)
	}

	ttl := time.Until(expiresAt)
	if ttl <= 0 {
		ttl = 8 * time.Hour
	}

	pipe := r.cli.Pipeline()

	setCmd := pipe.SetXX(ctx, key, data, ttl)

	expiryScore := float64(expiresAt.Unix())
	pipe.ZAdd(ctx, r.expiryIndexKey, redis.Z{
		Score:  expiryScore,
		Member: sandbox.SessionID,
	})

	lastActivity := sandbox.CreatedAt
	if sandbox.LastActivity != nil {
		lastActivity = *sandbox.LastActivity
	}
	pipe.ZAdd(ctx, r.lastActivityIndexKey, redis.Z{
		Score:  float64(lastActivity.Unix()),
		Member: sandbox.SessionID,
	})

	_, err = pipe.Exec(ctx)
	if err != nil {
		return err
	}

	if !setCmd.Val() {
		return ErrNotFound
	}

	return nil
}

func (r *redisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := r.sessionPrefix + sessionID

	pipe := r.cli.Pipeline()

	pipe.Del(ctx, key)

	pipe.ZRem(ctx, r.expiryIndexKey, sessionID)

	pipe.ZRem(ctx, r.lastActivityIndexKey, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

func (r *redisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	sessionIDs, err := r.getZSetByScore(ctx, r.expiryIndexKey, "-inf", before.Unix(), limit)
	if err != nil {
		return nil, err
	}

	return r.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (r *redisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	sessionIDs, err := r.getZSetByScore(ctx, r.lastActivityIndexKey, "-inf", before.Unix(), limit)
	if err != nil {
		return nil, err
	}

	return r.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (r *redisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	key := r.sessionPrefix + sessionID

	exists, err := r.cli.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	pipe := r.cli.Pipeline()
	pipe.ZAdd(ctx, r.lastActivityIndexKey, redis.Z{
		Score:  float64(at.Unix()),
		Member: sessionID,
	})
	_, err = pipe.Exec(ctx)
	return err
}

func (r *redisStore) Close() error {
	return r.cli.Close()
}

func (r *redisStore) getZSetByScore(ctx context.Context, key string, min string, max int64, limit int64) ([]string, error) {
	result, err := r.cli.ZRangeByScore(ctx, key, &redis.ZRangeBy{
		Min:    min,
		Max:    fmt.Sprintf("%d", max),
		Offset: 0,
		Count:  limit,
	}).Result()
	if err != nil {
		return nil, err
	}
	return result, nil
}

func (r *redisStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return []*types.SandboxInfo{}, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = r.sessionPrefix + id
	}

	pipe := r.cli.Pipeline()
	cmds := make([]*redis.BytesCmd, len(keys))
	for i, key := range keys {
		cmds[i] = pipe.Get(ctx, key)
	}

	_, err := pipe.Exec(ctx)
	if err != nil && err != redis.Nil {
		return nil, err
	}

	var result []*types.SandboxInfo
	for _, cmd := range cmds {
		data, err := cmd.Result()
		if err == redis.Nil {
			continue
		}
		if err != nil {
			return nil, err
		}

		var sandbox types.SandboxInfo
		if err := json.Unmarshal(data, &sandbox); err != nil {
			continue
		}
		result = append(result, &sandbox)
	}

	return result, nil
}

